        # Left movement
        var movement = -speed * delta
        if get_node("CharacterBody3D") is CharacterBody3D:
            get_node("CharacterBody3D").linear_velocity = Vector3(movement, 0, 0)
        else:
            get_node("KinematicBody2D").linear_velocity = Vector2(movement, 0)

    # ... (rest of the code remains the same)

    # Camera movement
    var camera = get_node("Camera")
